  "type": "LEARNING_CARD",
  "lessonText": "Share your personal experiences with fever and cold sensations.",
  "data": {
    "learningCards": [
      {
        "title": "Fever Experiences",
        "content": "Reflect on your past fevers. Consider:\n- Duration of fever\n- Symptoms experienced\n- Remedies used",
        "layout": "standard"
      },
      {
        "title": "Cold Sensations",
        "content": "Think about times you've felt unusually cold. Focus on:\n- Triggers for cold sensations\n- Physical reactions\n- Coping strategies",
        "layout": "standard"
      },
      {
        "title": "Comparative Reflections",
        "content": "Compare your fever and cold experiences. Ask yourself:\n- How did you manage each?\n- What were the emotional impacts?\n- Did you seek medical advice?",
        "layout": "standard"
      }
    ]
  }
}
